import os
import re

input_files = os.listdir("input")
pdf_files = [f for f in input_files if f.endswith(".pdf")]

# Extract first author and year from studies list
def get_author_year(citation):
    # Match something like "Author, ... (Year)"
    match = re.search(r"^([^,]+),.*?\((\d{4})\)", citation)
    if match:
        return match.group(1).strip(), match.group(2)
    return None, None

def slugify(text):
    return re.sub(r'[\W_]+', '', text).lower()

matches = []
missing = []

for study in studies:
    author, year = get_author_year(study)
    found = False
    
    if author and year:
        # Check if author and year are in any filename
        for pdf in pdf_files:
            if author.lower() in pdf.lower() and year in pdf:
                matches.append((study, pdf))
                found = True
                break
        
        if not found:
            # Try a looser match (author only) if unique enough
            # But let's stay with author+year for accuracy
            pass

    if not found:
        # Check if the study name (short form) is in the mapping if we have it
        # Since I don't have the mapping here, I'll rely on common patterns
        missing.append(study)

print(f"Total studies: {len(studies)}")
print(f"Matched: {len(matches)}")
print(f"Missing: {len(missing)}")

if missing:
    print("\nMissing Studies:")
    for m in missing:
        print(f"- {m}")
